  /**
   * Find matching records for brand+model+issue (optionally filtered by tier).
   * Returns [] if nothing matches.
   */
  function findEstimates(brand, model, issueTypeCsvName, tier) {
    return RECORDS.filter(function (r) {
      return r.brand === brand &&
             r.model === model &&
             r.issueType === issueTypeCsvName &&
             (tier ? r.tier === tier : true);
    });
  }

  /**
   * Returns all 3 tier options (Premium / Standard / Compatible) for a combo.
   */
  function getAllTierOptions(brand, model, issueTypeCsvName) {
    return findEstimates(brand, model, issueTypeCsvName, null);
  }

  /**
   * Returns a single best estimate.
   * tier preference: Premium (OEM) > Standard (HQ) > Compatible (Budget).
   */
  function getEstimate(brand, model, issueTypeCsvName, preferredTier) {
    var matches = findEstimates(brand, model, issueTypeCsvName, null);
    if (matches.length === 0) return null;
    if (preferredTier) {
      var exact = matches.filter(function (r) { return r.tier === preferredTier; });
      if (exact.length > 0) return exact[0];
    }
    var pref = ["Premium (OEM)", "Standard (HQ)", "Compatible (Budget)"];
    matches.sort(function (a, b) { return pref.indexOf(a.tier) - pref.indexOf(b.tier); });
    return matches[0];
  }

